#include <iostream>

class Point {
private:
    int x;
    int y;

public:
    Point(int x_coord = 0, int y_coord = 0) : x(x_coord), y(y_coord) {}

    int getX() const { return x; }
    int getY() const { return y; }

    void setX(int val) { x = val; }
    void setY(int val) { y = val; }

    Point& operator++() {
        setX(getX() + 1);
        setY(getY() + 1);
        return *this;
    }

    void print() const {
        std::cout << "(" << getX() << ", " << getY() << ")";
    }
};

int main() {
    Point p(10, 20);
    std::cout << "Original point: ";
    p.print();
    std::cout << std::endl;

    ++p;
    std::cout << "After ++p: ";
    p.print();
    std::cout << std::endl;

    Point& p_ref = ++p;
    std::cout << "After ++p (via ref): ";
    p_ref.print();
    std::cout << std::endl;

    p_ref.setX(100);
    std::cout << "After p_ref.setX(100): ";
    p.print();
    std::cout << std::endl;

    return 0;
}
